import { ADD_INGRIDIENT_TO_BAR, REMOVE_INGRIDIENT_IN_BAR } from '../actions/types'


const initialState = []


export function ingridientsReducer(state = initialState, action) {
    switch (action.type) {
        case ADD_INGRIDIENT_TO_BAR:
            return [...state, action.payload]
        case REMOVE_INGRIDIENT_IN_BAR:
            return [...action.payload]
        default:
            return state
    }
}