import { combineReducers } from 'redux'
import { ingridientsReducer } from './ingridients'
import { dataReducer } from './data'
import { basketReducer } from './basket'
import { availableCoctailsReducer } from './availableCocktails'
import { fetchCoctailsReducer } from './fetchCoctailsReducer'


export const rootReducer = combineReducers({
    data: dataReducer,
    bar: ingridientsReducer,
    basket: basketReducer,
    availableCoctails: availableCoctailsReducer,
    fetchedCoctails: fetchCoctailsReducer
})