import React from 'react'
import { useDispatch, useSelector } from 'react-redux'
import { fetchCoctails } from '../../actions/fetchCoctails'
import './RandomCoctails.scss'
import RandomCoctailItem from '../../components/RandomCoctailsItem/RandomCoctailItem'

const RandomCoctails = () => {
    const dispatch = useDispatch()
    const coctailData = useSelector(store => store.fetchedCoctails.fetchedPosts)


    if (coctailData.length === 0) {
        return (
            <div className="random-coctails">
                <div className="container">
                    <button className="random-coctails__btn" onClick={() => dispatch(fetchCoctails())}>Получить коктейль</button>
                </div>
            </div>
        )
    }
    return (
        <RandomCoctailItem {...coctailData.drinks} key={coctailData.drinks[0].idDrink} />
    )
}

export default RandomCoctails