import React, { Component } from 'react'
import './AvailableCoctails.scss'
import Coctail from '../Coctail'


export default class AvailableCoctails extends Component {

    render() {
        let coctails;

        if(this.props.availableCoctails.prod.length > 0){
            coctails = this.props.availableCoctails.prod.map((item) => {
                return (
                    <Coctail key={item.idDrink} coctailInfo={item} />
                )
            })
        }

        return (
            <>
                <div className="available-coctails">
                    <div className="container">
                        <h2 className="available-coctails__title">Доступные коктейли</h2>
                        <div className="available-coctails__blocks">
                            {coctails}
                        </div>
                    </div>
                </div>
            </>
        )
    }
}