import React from 'react'
import { Link } from 'react-router-dom'
import { connect } from 'react-redux'
import './Basket.scss'
import { ReactComponent as BasketSvg } from '../../assets/svg/basket.svg'


const Basket = (props) => {
    const { basket } = props
    let basketElem;

    if (basket.length === 0) {
        basketElem = (<div className="basket">
            <Link className="basket__link" to='/full-basket'>
                <div className="basket__inner">
                    <BasketSvg className="basket__svg" />
                    <span className="basket__text">Корзина пуста</span>
                </div>
            </Link>
        </div>)
    } else {
        basketElem = (
            <div className="basket">
                <Link className="basket__link" to="/full-basket">
                    <div className="basket__inner">
                        <BasketSvg className="basket__svg" />
                        <span className="basket__text">Корзина</span>
                        <span className="basket__count">{basket.length}</span>
                    </div>
                </Link>
            </div>
        )
    }

    return (
        <>
            {basketElem}
        </>
    )
}


const mapStateToProps = store => {
    return {
        basket: store.basket,
    }
}

export default connect(mapStateToProps)(Basket)