import React from 'react'
import { Link } from 'react-router-dom'
import './Header.scss'
import Basket from '../../containers/Basket'


const Header = () => {
    return (
        <>
            <div className="header">
                <div className="header-top">
                    <div className="container header__container">
                        <Link className="header__logo" to='/Coctail-app/'>CoctailApp</Link>
                        <span className="header__detail">SPA</span>
                        <nav>
                            <ul className="header__list">
                                <li className="header__item">
                                    <Link className="header__link" to='/Coctail-app/categories/2'>Незабываемые</Link>
                                </li>
                                <li className="header__item">
                                    <Link className="header__link" to='/Coctail-app/categories/1'>Современная классика</Link>
                                </li>
                                <li className="header__item">
                                    <Link className="header__link" to='/Coctail-app/categories/3'>Напитки новой эры</Link>
                                </li>
                            </ul>
                        </nav>
                    </div>
                </div>

                <div className="header-bottom">
                    <div className="container header-bottom__container">
                        <Link to='/Coctail-app/about' className="header-bottom__link">
                            <span className="header-bottom__about">О приложении</span>
                        </Link>
                        <Link to='/Coctail-app/the-coctail-db' className="header-bottom__link">
                            <span className="header-bottom__about">TheCoctailDB</span>
                        </Link>
                        <Basket />
                    </div>
                </div>
            </div>
        </>
    );
};

export default Header;