import React from 'react'


const Ingridient = props => {
    const { item, addBar } = props;

    const addBarWrap = () => {
        addBar(item)
    }

    return (
        <li>
            <div className="my-bar__ingridient">
                <span>{item.name}</span>
                <button className="my-bar__add" data-name={item.name} onClick={addBarWrap}>+</button>
            </div>
        </li>
    )
}


export default Ingridient