import React from 'react'
import './Table.scss'

const Table = ({composition}) => {
    let tableRows = composition.map((item) => {
        return (
            <tr key={composition.indexOf(item)}>
                <td>{item.name}</td>
                <td>{item.quantity}</td>
                <td className="table__measure">{item.measure}</td>
            </tr>
        )
    })

    return (
        <>
            <table className='table'>
                <thead>
                    <tr>
                        <th>Необходимые ингредиенты</th>
                        <th></th>
                        <th></th>
                    </tr>

                </thead>
                <tbody>
                    {tableRows}
                </tbody>
            </table>
        </>
    )
}


export default Table