import { FETCH_COCTAILS } from '../actions/types'



export function fetchCoctails() {
    return async dispatch => {
        const responce = await fetch('https://www.thecocktaildb.com/api/json/v1/1/random.php')
        const json = await responce.json()
        console.log('json', json)
        dispatch({ type: FETCH_COCTAILS, payload: json })
    }
}