import React from 'react'
import './BarItem.scss'


const BarItem = (barItem) => {
    const { name, price, removeFromBar, addBasket, img } = barItem;

    return (
        <div className="bar-item" data-name={name}>
            <div className="bar-item__inner">
                <div className="bar-item-front">
                    <img className="bar-item__img" src={img} alt={name} />
                    <p className="bar-item__name">{name}</p>
                </div>
                <div className="bar-item-back">
                    <button className="bar-item__remove" title="Удалить из бара" onClick={() => removeFromBar(barItem)}>X</button>
                    <div className="bar-item__wrap-btn">
                        <button className="bar-item__btn" onClick={() => addBasket(barItem)}>Добавить в корзину</button>
                    </div>
                    <span className="bar-item__price">Цена:</span>
                    <span className="bar-item__count">{price} руб.</span>
                </div>
            </div>
        </div>
    )
}


export default BarItem