import React from 'react'
import { Link } from 'react-router-dom'
import './Coctail.scss'


const Coctail = (props) => {
	const { idDrink, image, nameDrink } = props.coctailInfo

	if (!props.coctailInfo) {
		return (
			<div>Коктейля нет</div>
		)
	}

	return (
		<div className="coctail" key={idDrink}>
			<Link className="coctail__link" to={`/coctail/${idDrink}`}>
				<div className="coctail__inner">
					<img className="coctail__image" src={image} alt={nameDrink} />
					<p className="coctail__name">{nameDrink}</p>
				</div>
			</Link>
		</div>
	)
}

export default Coctail