import { FETCH_COCTAILS } from '../actions/types'

const initialState = {
    fetchedPosts: []
}


export function fetchCoctailsReducer(state = initialState, action) {
    switch (action.type) {
        case FETCH_COCTAILS:
            return { ...state, fetchedPosts: action.payload }
        default:
            return state
    }
}